var book = Book.modelFindOne(["id" => req.bookId]);
if (book.available) {
    var due = req.dueDate;
    var record = BorrowRecord.modelCreate([
        "Book_id" => book.id,
        "Member_id" => req.memberId,
        "borrowedAt" => req.borrowedAt,
        "dueDate" => due
    ]);
    Book.modelUpdate(["id" => book.id], ["available" => false]);
    return json(["success" => true, "borrowId" => record.id]);
} else {
    return json(["error" => "Book is currently unavailable"]);
}

var record = BorrowRecord.modelFindOne(["Book_id" => req.bookId, "returnedAt" => null]);
if (record) {
    var returnedTime = req.returnedAt;
    BorrowRecord.modelUpdate(["id" => record.id], ["returnedAt" => returnedTime]);
    Book.modelUpdate(["id" => req.bookId], ["available" => true]);

    if (returnedTime > record.dueDate) {
        var denda = Fine.modelCreate([
            "BorrowRecord_id" => record.id,
            "Member_id" => record.Member_id,
            "amount" => 50000.00,
            "isPaid" => false
        ]);
        return json(["success" => true, "status" => "returned_with_fine", "fineAmount" => 50000.00]);
    }
    return json(["success" => true, "status" => "returned_on_time"]);
} else {
    return json(["error" => "No active borrow record found"]);
}

